import { useSelector } from 'react-redux';
import { useLSSync } from '@/src/app/layout/Default/lib';
import { settingsSliceName, setTheme } from '@/src/shared/store/slices';
import type { IRootState } from '@/src/shared/store';


export function useDLSyncLogic() {
    const theme = useSelector((state: IRootState) => state.settings.theme);

    const initSyncData = [
        {
            namespace: settingsSliceName,
            items: [
                {
                    key: 'theme',
                    value: theme,
                    reducer: setTheme
                }
            ]
        }
    ];

    const trackableData = [ theme ];

    useLSSync(initSyncData, trackableData);
}
