import { useEffect, useRef } from 'react';
import { getItem, setItem } from '@/src/shared/utils/localStore';
import { useDispatch } from 'react-redux';
import type { TRootDispatch } from '@/src/shared/store';
import type { IUseLSSyncData  } from './types';


export function useLSSync(syncData: IUseLSSyncData[], trackableData: any[]): void {
  const dispatch = useDispatch<TRootDispatch>();
  const prevDataRef = useRef<any[]>(trackableData);

  useEffect(() => {
    syncData.forEach(({ namespace, items }) => {
      const nsData = getItem<Record<string, any>>(namespace) || {};
      const newNsData: Record<string, any> = { ...nsData };

      items.forEach(({ key, value, reducer }, index) => {
        const prevValue = prevDataRef.current[index];

        if (prevValue !== value) {
          newNsData[key] = value;
          dispatch(reducer(value));
        }
      });

      setItem(namespace, newNsData);
    });

    prevDataRef.current = trackableData;
  }, [syncData, trackableData, dispatch]);
}
